import 'package:firebase_functions/firebase_functions.dart';

void main(List<String> args) {
  // Use 'functions' instead of 'fireUp' if the alias is causing issues
  functions.register(args, () {
    
    functions.https.onRequest(
      name: 'helloWorld',
      options: const HttpsOptions(
        // In the latest Dart SDK for Firebase, cors is often a boolean or a specific object
        cors: true, 
        // maxInstances takes a raw integer, not a class wrapper
        maxInstances: 10,
      ),
      (HttpRequest request) async {
        // Use the built-in response method from the library
        return Response(200, body: 'Hello from Dart Functions!');
      },
    );

  });
}